import {
  noop,
  resolve as _resolve
} from '../-internal';


export default function resolve(object, label) {
  
  let Constructor = this;

  if (object && typeof object === 'object' && object.constructor === Constructor) {
    return object;
  }

  let promise = new Constructor(noop, label);
  _resolve(promise, object);
  return promise;
}
